import random

def detect_flakiness(func, n_runs=10):
    seen_values = set()
    for _ in range(n_runs):
        try:
            result = func()
            seen_values.add(result)
        except Exception:
            return True
    return len(seen_values) > 1

def test_flaky_function():
    return random.choice([True, False])

def test_stable_failure():
    return False

def test_stable_success():
    return True

def test_type_consistency():
    return random.choice([1, True])

assert detect_flakiness(test_flaky_function) == True
assert detect_flakiness(test_stable_failure) == False
assert detect_flakiness(test_stable_success) == False
assert detect_flakiness(test_type_consistency) == False

print("All tests passed!")
