import random

def detect_flakiness(func, n_runs=10):
    results = []
    for _ in range(n_runs):
        try:
            result = func()
            results.append(result)
        except Exception:
            results.append(None)
            break
    if not results:
        return False
    unique_results = set(results)
    return len(unique_results) > 1

def test_flakiness():
    def flaky_func():
        return random.choice([1, 2, 3])

    def stable_func():
        return 1

    assert detect_flakiness(flaky_func) == True
    assert detect_flakiness(stable_func) == False
